import React, { useState } from "react";
import axios from "axios";
import { Line, Bar } from "react-chartjs-2";
import { motion } from "framer-motion";
import AffiliateBanner from "./AffiliateBanner";

import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend
);

function IndianStockDetails() {
  const [symbol, setSymbol] = useState("TCS.NS");
  const [data, setData] = useState(null);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleFetch = async () => {
    setError("");
    setData(null);
    if (!symbol.trim()) {
      setError("Please enter a stock symbol.");
      return;
    }

    setLoading(true);
    try {
      const res = await axios.get(`http://localhost:3000/api/stocks/${symbol}`);
      setData(res.data);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch data.");
    }
    setLoading(false);
  };

  const renderPriceChart = () => {
    if (!data?.historical?.length) return null;

    const labels = data.historical.map(d =>
      new Date(d.date).toLocaleDateString("en-IN", { month: "short", day: "numeric" })
    );
    const prices = data.historical.map(d => d.close);

    return (
      <motion.div
        style={chartCardStyle}
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <h3 style={cardHeadingStyle}>📈 Price History</h3>
        <Line
          data={{
            labels,
            datasets: [
              {
                label: `${data.symbol} Closing Price`,
                data: prices,
                borderColor: "#0ef0ad",
                backgroundColor: "rgba(14, 240, 173, 0.2)",
                fill: true,
                tension: 0.3,
              },
            ],
          }}
          height={100}
          options={{
            plugins: { legend: { display: false } },
            scales: {
              x: { ticks: { color: "#aaa" } },
              y: { ticks: { color: "#aaa" } },
            },
          }}
        />
      </motion.div>
    );
  };

  const renderBalanceSheet = () => {
    if (!data?.balanceSheet?.length) return null;

    const labels = data.balanceSheet.map(d => d.year);
    const assets = data.balanceSheet.map(d => d.assets);
    const liabilities = data.balanceSheet.map(d => d.liabilities);
    const equity = data.balanceSheet.map(d => d.equity);

    return (
      <motion.div
        style={chartCardStyle}
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <h3 style={cardHeadingStyle}>📄 Balance Sheet Overview</h3>
        <Bar
          data={{
            labels,
            datasets: [
              {
                label: "Assets",
                data: assets,
                backgroundColor: "#36a2eb",
              },
              {
                label: "Liabilities",
                data: liabilities,
                backgroundColor: "#ff6384",
              },
              {
                label: "Equity",
                data: equity,
                backgroundColor: "#0ef0ad",
              },
            ],
          }}
          height={100}
          options={{
            plugins: { legend: { position: "bottom" } },
            scales: {
              x: { ticks: { color: "#aaa" } },
              y: { ticks: { color: "#aaa" } },
            },
          }}
        />
      </motion.div>
    );
  };

  const renderProfitLoss = () => {
    if (!data?.profitLoss?.length) return null;

    const labels = data.profitLoss.map(d => d.year);
    const revenue = data.profitLoss.map(d => d.revenue);
    const profit = data.profitLoss.map(d => d.profit);

    return (
      <motion.div
        style={chartCardStyle}
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <h3 style={cardHeadingStyle}>📄 Profit & Loss</h3>
        <Bar
          data={{
            labels,
            datasets: [
              {
                label: "Revenue",
                data: revenue,
                backgroundColor: "#ffa500",
              },
              {
                label: "Profit",
                data: profit,
                backgroundColor: "#4caf50",
              },
            ],
          }}
          height={100}
          options={{
            plugins: { legend: { position: "bottom" } },
            scales: {
              x: { ticks: { color: "#aaa" } },
              y: { ticks: { color: "#aaa" } },
            },
          }}
        />
      </motion.div>
    );
  };

  const fundamentals = data
    ? [
        { label: "Market Cap", value: data.marketCap },
        { label: "PE Ratio", value: data.peRatio },
        { label: "Dividend Yield (%)", value: data.dividendYield },
        { label: "52-Week High", value: data.fiftyTwoWeekHigh },
        { label: "52-Week Low", value: data.fiftyTwoWeekLow },
        { label: "ROE (%)", value: data.roe },
        { label: "ROCE (%)", value: data.roce },
        { label: "Book Value", value: data.bookValue },
        { label: "Face Value", value: data.faceValue },
      ]
    : [];

  const renderList = (arr, title) =>
    arr?.length > 0 && (
      <motion.div
        style={chartCardStyle}
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <h3 style={cardHeadingStyle}>{title}</h3>
        <ul style={listStyle}>
          {arr.map((item, i) => (
            <li key={i} style={{ marginBottom: "0.5rem" }}>
              {item}
            </li>
          ))}
        </ul>
      </motion.div>
    );

  return (
    <motion.div
      style={pageStyle}
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.5 }}
    >
      <h2 style={headingStyle}>Indian Stock Details</h2>

      <div style={searchContainer}>
        <input
          type="text"
          placeholder="Enter symbol (e.g. TCS.NS)"
          value={symbol}
          onChange={(e) => setSymbol(e.target.value)}
          style={inputStyle}
        />
        <motion.button
          onClick={handleFetch}
          style={buttonStyle}
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
          disabled={loading}
        >
          {loading ? "Loading..." : "Fetch"}
        </motion.button>
      </div>

      {error && (
        <motion.p
          style={{ color: "#ff4d4f", marginTop: "10px" }}
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
        >
          {error}
        </motion.p>
      )}

      {data && (
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          style={{ marginTop: "30px" }}
        >
          <h3 style={companyTitle}>
            {data.name} ({data.symbol})
          </h3>
          <h1 style={{
            color: data.change > 0 ? "lime" : "red",
            fontSize: "2.5rem",
            marginBottom: "1rem",
          }}>
            ₹{data.price?.toLocaleString("en-IN")} 
            &nbsp;|&nbsp;
            {data.change > 0 ? "▲" : "▼"} {data.change} ({data.percentChange}%)
          </h1>

          <motion.div
            style={fundamentalsGrid}
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.2 }}
          >
            {fundamentals.map((item, i) => (
              <motion.div
                key={i}
                style={fundamentalsCard}
                whileHover={{ scale: 1.05 }}
              >
                <p style={fundamentalLabel}>{item.label}</p>
                <p style={fundamentalValue}>
                  {item.value !== undefined && item.value !== null
                    ? item.label.includes("₹") || typeof item.value === "number"
                      ? `₹${Number(item.value).toLocaleString("en-IN")}`
                      : item.value
                    : "-"}
                </p>
              </motion.div>
            ))}
          </motion.div>

          {renderPriceChart()}
          {renderBalanceSheet()}
          {renderProfitLoss()}
          {renderList(data.peers, "👨‍👩‍👧‍👦 Peers")}
          {renderList(data.pros, "✅ Pros")}
          {renderList(data.cons, "❌ Cons")}
        </motion.div>
      )}

      <AffiliateBanner />

      {/* Add a coffee button if you want */}
      <div style={{ textAlign: "center", marginTop: "40px" }}>
        <a
          href="https://www.buymeacoffee.com/yourname"
          target="_blank"
          rel="noopener noreferrer"
          style={{
            display: "inline-block",
            backgroundColor: "#FFDD00",
            color: "#000",
            fontWeight: "bold",
            fontSize: "18px",
            padding: "12px 24px",
            borderRadius: "8px",
            textDecoration: "none",
            boxShadow: "0 2px 5px rgba(0,0,0,0.3)",
            transition: "transform 0.2s",
          }}
          onMouseOver={(e) => (e.currentTarget.style.transform = "scale(1.05)")}
          onMouseOut={(e) => (e.currentTarget.style.transform = "scale(1)")}
        >
          ☕ Buy Me a Coffee
        </a>
      </div>
    </motion.div>
  );
}

